import React, { useEffect, useState, useCallback } from 'react';
import { Users as UsersIcon, Ticket, Wallet, ShoppingCart, Loader2, RefreshCcw, TrendingUp, ArrowUpRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole } from '../types';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ revenue: 0, sold: 0, stock: 0, users: 0 });
  const [recentSales, setRecentSales] = useState<any[]>([]);

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;

      const { data: profile } = await db.from('users').select('role, tenant_id').eq('id', user.id).maybeSingle();
      if (!profile) return;

      const isAdmin = profile.role === UserRole.ADMIN_GLOBAL;
      const tId = profile.tenant_id;

      // Helper pour appliquer le filtre tenant si nécessaire
      const applyTenantFilter = (query: any) => {
        if (!isAdmin && tId) return query.eq('tenant_id', tId);
        return query;
      };

      // Requêtes optimisées : on utilise { count: 'exact', head: true } pour ne pas télécharger les données inutilement
      const [stockRes, soldRes, revRes, userRes, salesRes] = await Promise.all([
        applyTenantFilter(db.from('tickets').select('*', { count: 'exact', head: true })).eq('status', 'NEUF'),
        applyTenantFilter(db.from('tickets').select('*', { count: 'exact', head: true })).eq('status', 'VENDU'),
        applyTenantFilter(db.from('sales_history').select('amount_paid')), // On a besoin des montants pour la somme
        applyTenantFilter(db.from('users').select('*', { count: 'exact', head: true })),
        applyTenantFilter(db.from('sales_history').select('*, tickets(username, ticket_profiles(name))')).order('sold_at', { ascending: false }).limit(6)
      ]);

      setStats({
        revenue: (revRes.data || []).reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0) || 0,
        sold: soldRes.count || 0,
        stock: stockRes.count || 0,
        users: userRes.count || 0
      });
      setRecentSales(salesRes.data || []);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchDashboardData(); }, [fetchDashboardData]);

  if (loading) return <div className="h-[60vh] flex flex-col items-center justify-center"><Loader2 className="w-12 h-12 text-brand-600 animate-spin mb-4 opacity-20" /><p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Synchronisation Cloud...</p></div>;

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-8">
        <div><h1 className="text-4xl font-black text-slate-900 tracking-tight italic leading-none mb-3">Tableau de Bord</h1><p className="text-slate-400 font-medium text-lg">Résumé de l'activité de votre infrastructure WiFi.</p></div>
        <div className="flex items-center gap-4">
          <button onClick={() => navigate('/sales')} className="bg-brand-600 hover:bg-brand-700 text-white px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-2xl shadow-brand-100 transition-all active:scale-95"><ShoppingCart className="w-5 h-5" /> Nouvelle Vente</button>
          <button onClick={fetchDashboardData} className="p-5 bg-white border border-slate-100 rounded-2xl text-slate-300 hover:text-brand-600 transition-all shadow-sm active:rotate-180 duration-500"><RefreshCcw className="w-6 h-6" /></button>
        </div>
      </header>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Chiffre d'Affaires" value={`${stats.revenue.toLocaleString()}`} unit="GNF" icon={<Wallet />} color="bg-brand-600" />
        <StatCard label="Tickets Vendus" value={stats.sold} unit="Ventes" icon={<TrendingUp />} color="bg-emerald-600" />
        <StatCard label="Stock Disponible" value={stats.stock} unit="Vouchers" icon={<Ticket />} color="bg-indigo-600" />
        <StatCard label="Utilisateurs" value={stats.users} unit="Membres" icon={<UsersIcon />} color="bg-slate-900" />
      </div>
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-10 items-start">
        <div className="xl:col-span-2 bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-10 border-b border-slate-50 flex items-center justify-between"><h3 className="font-black text-slate-900 uppercase tracking-tight">Transactions récentes</h3><button onClick={() => navigate('/history')} className="text-[10px] font-black text-brand-600 uppercase tracking-widest hover:underline">Journal complet</button></div>
          <div className="divide-y divide-slate-50">
            {recentSales.length > 0 ? recentSales.map((sale, i) => (
              <div key={i} className="p-8 flex items-center justify-between hover:bg-slate-50 transition-all group">
                <div className="flex items-center gap-6">
                  <div className="w-12 h-12 bg-slate-100 rounded-2xl flex items-center justify-center font-black text-slate-400 text-xs group-hover:bg-brand-50 group-hover:text-brand-600 transition-colors">#</div>
                  <div><p className="font-black text-slate-900 text-base tracking-tight leading-none mb-1.5">{sale.tickets?.username || 'Ticket Inconnu'}</p><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{sale.tickets?.ticket_profiles?.name || 'Offre Standard'}</p></div>
                </div>
                <div className="text-right"><p className="font-black text-slate-900 text-base">{Number(sale.amount_paid).toLocaleString()} GNF</p><p className="text-[10px] font-bold text-slate-300 uppercase mt-1">{new Date(sale.sold_at).toLocaleTimeString()}</p></div>
              </div>
            )) : <div className="p-32 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">Aucune donnée</div>}
          </div>
        </div>
        <div className="bg-brand-600 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
          <h3 className="text-xl font-black uppercase tracking-tight mb-8 relative z-10">Performance</h3>
          <div className="space-y-6 relative z-10">
             <div className="bg-white/10 backdrop-blur-md p-6 rounded-3xl border border-white/10 flex items-center justify-between"><div><p className="text-[9px] font-black text-brand-200 uppercase tracking-widest mb-1">Stock</p><p className="text-2xl font-black">{stats.stock}</p></div><div className="bg-emerald-500/20 text-emerald-300 px-3 py-1 rounded-full text-[9px] font-black tracking-widest">ACTIF</div></div>
             <div className="bg-white/10 backdrop-blur-md p-6 rounded-3xl border border-white/10 flex items-center justify-between"><div><p className="text-[9px] font-black text-brand-200 uppercase tracking-widest mb-1">Ventes Totales</p><p className="text-2xl font-black">{stats.sold}</p></div><div className="bg-brand-500/20 text-brand-100 px-3 py-1 rounded-full text-[9px] font-black tracking-widest">STABLE</div></div>
          </div>
          <button onClick={() => navigate('/history')} className="w-full mt-10 py-5 bg-white text-brand-600 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl transition-all hover:scale-105">ANALYSE COMPLÈTE <ArrowUpRight className="w-4 h-4" /></button>
        </div>
      </div>
    </div>
  );
};
const StatCard = ({ label, value, unit, icon, color }: any) => (
  <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col justify-between group hover:border-brand-100 transition-all hover:shadow-2xl hover:-translate-y-1 duration-500">
    <div className={`w-14 h-14 ${color} rounded-2xl flex items-center justify-center text-white mb-8 shadow-xl group-hover:scale-110 transition-transform`}>{React.cloneElement(icon, { className: "w-6 h-6" })}</div>
    <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">{label}</p><div className="flex items-baseline gap-2"><h3 className="text-3xl font-black text-slate-900 tracking-tighter">{value}</h3><span className="text-[10px] font-black text-slate-300 uppercase">{unit}</span></div></div>
  </div>
);
export default Dashboard;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Mail, Lock, ArrowRight, ChevronLeft, Zap, ShieldCheck, Globe, AlertCircle, Loader2, WifiOff } from 'lucide-react';
import { db } from '../services/db';

const Login: React.FC = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true); setError(null);
    try {
      const { data, error: authError } = await db.auth.signInWithPassword({ email, password });
      if (authError) throw authError;
      if (data.user) {
        const { data: profile } = await db.from('users').select('tenant_id').eq('id', data.user.id).maybeSingle();
        navigate((!profile || !profile.tenant_id) ? '/complete-setup' : '/dashboard');
      }
    } catch (err: any) { setError(err.message || "Erreur lors de la connexion."); } finally { setIsLoading(false); }
  };

  return (
    <div className="min-h-screen bg-white flex font-sans text-slate-900">
      <div className="hidden lg:flex w-1/2 bg-brand-600 relative overflow-hidden flex-col justify-between p-16">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none"><div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] bg-white/10 rounded-full blur-3xl animate-pulse"></div><div className="absolute bottom-[-5%] right-[-5%] w-[40%] h-[40%] bg-indigo-300/20 rounded-full blur-3xl"></div></div>
        <div className="relative z-10"><Link to="/" className="flex items-center gap-3 mb-20 group"><div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-brand-600 font-black text-2xl shadow-xl shadow-brand-900/20 transition-transform group-hover:scale-110">G</div><span className="text-2xl font-black text-white tracking-tighter">Gestion_Hotspot</span></Link><h2 className="text-6xl font-black text-white leading-tight tracking-tighter mb-8">Pilotez votre <br /><span className="text-brand-100 italic">succès numérique.</span></h2><p className="text-brand-50 text-xl font-medium max-w-md leading-relaxed opacity-90">La plateforme n°1 en Afrique pour la gestion et la monétisation de réseaux WiFi professionnels.</p></div>
        <div className="relative z-10 grid grid-cols-2 gap-8"><div className="bg-white/10 backdrop-blur-md p-6 rounded-[2rem] border border-white/20"><div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center text-white mb-4"><Zap className="w-5 h-5 fill-current" /></div><p className="text-2xl font-black text-white mb-1">+12k</p><p className="text-[10px] font-black text-brand-100 uppercase tracking-widest">Tickets / Jour</p></div><div className="bg-white/10 backdrop-blur-md p-6 rounded-[2rem] border border-white/20"><div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center text-white mb-4"><Globe className="w-5 h-5" /></div><p className="text-2xl font-black text-white mb-1">24/7</p><p className="text-[10px] font-black text-brand-100 uppercase tracking-widest">Disponibilité Cloud</p></div></div>
      </div>
      <div className="w-full lg:w-1/2 flex items-center justify-center p-8 md:p-16">
        <div className="w-full max-w-md">
          <div className="mb-12"><button onClick={() => navigate('/')} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 font-bold text-xs tracking-widest uppercase mb-8 transition-colors group"><ChevronLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />Retour à l'accueil</button><h1 className="text-4xl font-black text-slate-900 tracking-tight mb-3">Ravi de vous revoir !</h1><p className="text-slate-400 font-medium">Accédez à votre console d'administration.</p></div>
          {error && (<div className="mb-6 p-5 bg-red-50 border border-red-100 rounded-3xl flex items-start gap-4 text-red-600 animate-in fade-in slide-in-from-top-4">{error.includes("Impossible") ? <WifiOff className="w-6 h-6 shrink-0 mt-0.5" /> : <AlertCircle className="w-6 h-6 shrink-0 mt-0.5" />}<p className="text-sm font-bold leading-relaxed">{error}</p></div>)}
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Adresse Email</label><div className="relative group"><Mail className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" /><input type="email" required placeholder="nom@agence.com" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50/50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-600 placeholder:text-slate-300 transition-all" /></div></div>
            <div className="space-y-2"><div className="flex justify-between items-center px-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Mot de passe</label></div><div className="relative group"><Lock className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" /><input type="password" required placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50/50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-600 placeholder:text-slate-300 transition-all" /></div></div>
