          </form>
          <div className="mt-4 text-center"><p className="text-sm font-medium text-slate-400">Pas encore de compte ? <Link to="/register-agency" className="text-brand-600 font-black uppercase text-[10px] tracking-widest hover:underline ml-1">Créer une agence</Link></p></div>
          <div className="mt-8 pt-8 border-t border-slate-50 flex items-center justify-center gap-6 opacity-40"><ShieldCheck className="w-5 h-5 text-slate-300" /><span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Connexion Sécurisée</span></div>
        </div>
      </div>
    </div>
  );
};
export default Login;

import React, { useState, useEffect, Suspense, lazy } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Menu, Loader2 } from 'lucide-react';
import { db } from './services/db';

const Sidebar = lazy(() => import('./components/Sidebar'));
const Landing = lazy(() => import('./pages/Landing'));
const Login = lazy(() => import('./pages/Login'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Sales = lazy(() => import('./pages/Sales'));
const Import = lazy(() => import('./pages/Import'));
const Stock = lazy(() => import('./pages/Stock'));
const History = lazy(() => import('./pages/History'));
const Agencies = lazy(() => import('./pages/Agencies'));
const Users = lazy(() => import('./pages/Users'));
const Resellers = lazy(() => import('./pages/Resellers'));
const Settings = lazy(() => import('./pages/Settings'));
const CompleteSetup = lazy(() => import('./pages/CompleteSetup'));
const RegisterAgency = lazy(() => import('./pages/RegisterAgency'));
const Subscriptions = lazy(() => import('./pages/Subscriptions'));
const Zones = lazy(() => import('./pages/Zones'));
const Profiles = lazy(() => import('./pages/Profiles'));
const PendingApproval = lazy(() => import('./pages/PendingApproval'));

const GlobalLoader = () => (
  <div className="h-screen w-full flex flex-col items-center justify-center bg-[#f8fafc]">
    <div className="relative"><div className="w-16 h-16 border-4 border-brand-100 border-t-brand-600 rounded-full animate-spin"></div></div>
    <p className="mt-6 text-[10px] font-black uppercase tracking-[0.4em] text-slate-400">Chargement Cloud...</p>
  </div>
);

const AppLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  return (
    <div className="flex h-screen bg-[#f8fafc] overflow-hidden flex-col">
      <div className="flex flex-1 overflow-hidden">
        <Suspense fallback={null}><Sidebar isOpen={sidebarOpen} setIsOpen={setSidebarOpen} /></Suspense>
        <div className="flex-1 flex flex-col h-full overflow-hidden relative">
          <header className="md:hidden bg-white border-b border-slate-100 p-4 flex items-center justify-between shrink-0 z-30">
            <div className="flex items-center gap-2"><div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-black">G</div><span className="font-black text-sm tracking-tighter">Hotspot Pro</span></div>
            <button onClick={() => setSidebarOpen(true)} className="p-2 bg-slate-50 rounded-xl text-slate-500"><Menu className="w-6 h-6" /></button>
          </header>
          <main className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar relative z-10">
            <div className="max-w-7xl mx-auto h-full pb-24">
              <Suspense fallback={<div className="flex items-center justify-center h-full"><Loader2 className="animate-spin text-slate-200" /></div>}>{children}</Suspense>
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [authState, setAuthState] = useState<{ hasTenant: boolean; isPending: boolean; isAdminGlobal: boolean; }>({ hasTenant: false, isPending: false, isAdminGlobal: false });

  const syncProfile = async (userId: string) => {
    try {
      const { data } = await db.from('users').select('*').eq('id', userId).maybeSingle();
      if (data) {
        let subStatus = 'ACTIF';
        if (data.tenant_id) {
            const { data: t } = await db.from('tenants').select('*').eq('id', data.tenant_id).maybeSingle();
            if (t) subStatus = t.subscription_status;
        }
        setAuthState({ hasTenant: !!data.tenant_id, isPending: subStatus === 'EN_ATTENTE', isAdminGlobal: data.role === 'ADMIN_GLOBAL' });
      }
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => {
    // Initial fetch
    db.auth.getUser().then(({ data: { user } }) => {
      setSession(user ? { user } : null);
      if (user) syncProfile(user.id); else setLoading(false);
    });

    // Listen for auth changes (Login, Logout, Updates)
    const { data: { subscription } } = db.auth.onAuthStateChange((event, session) => {
        console.log("Auth Event:", event);
        if (event === 'SIGNED_OUT') {
            setSession(null);
            setAuthState({ hasTenant: false, isPending: false, isAdminGlobal: false });
            setLoading(false);
        } else if (session?.user) {
            setSession({ user: session.user });
            syncProfile(session.user.id);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (loading) return <GlobalLoader />;

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={!session ? <Landing /> : <Navigate to="/dashboard" replace />} />
        <Route path="/login" element={!session ? <Login /> : <Navigate to="/dashboard" replace />} />
        <Route path="/register-agency" element={!session ? <RegisterAgency /> : <Navigate to="/dashboard" replace />} />
        {session ? (
          <>
            <Route path="/complete-setup" element={(!authState.hasTenant && !authState.isAdminGlobal) ? <CompleteSetup onSetupComplete={() => session?.user && syncProfile(session.user.id)} /> : <Navigate to="/dashboard" replace />} />
            <Route path="/pending" element={authState.isPending ? <PendingApproval /> : <Navigate to="/dashboard" replace />} />
            <Route path="/*" element={
              (authState.isAdminGlobal || (authState.hasTenant && !authState.isPending)) ? (
                <AppLayout>
                  <Routes>
                    <Route path="/dashboard" element={<Dashboard />} />
                    <Route path="/sales" element={<Sales />} />
                    <Route path="/import" element={<Import />} />
                    <Route path="/stock" element={<Stock />} />
                    <Route path="/history" element={<History />} />
                    <Route path="/agencies" element={<Agencies />} />
                    <Route path="/users" element={<Users />} />
                    <Route path="/resellers" element={<Resellers />} />
                    <Route path="/settings" element={<Settings />} />
                    <Route path="/subscriptions" element={<Subscriptions />} />
                    <Route path="/zones" element={<Zones />} />
                    <Route path="/profiles" element={<Profiles />} />
                    <Route path="*" element={<Navigate to="/dashboard" replace />} />
                  </Routes>
                </AppLayout>
              ) : ( <Navigate to={!authState.hasTenant ? "/complete-setup" : "/pending"} replace /> )
            } />
          </>
        ) : ( <Route path="*" element={<Navigate to="/login" replace />} /> )}
      </Routes>
    </HashRouter>
  );
};
export default App;

-- INITIALISATION DE LA BASE DE DONNÉES GESTION_HOTSPOT

-- 1. Tables de base
-- Table des Tenants (Agences)
create table public.tenants (
  id uuid default gen_random_uuid() primary key,
  name text not null,
  subscription_status text default 'EN_ATTENTE', -- EN_ATTENTE, ACTIF, SUSPENDU
  subscription_end_at timestamptz,
  created_at timestamptz default now()
);

-- Table des Utilisateurs (Extension de auth.users)
create table public.users (
  id uuid references auth.users on delete cascade primary key,
  full_name text,
  email text,
  role text default 'CLIENT', -- ADMIN_GLOBAL, GESTIONNAIRE_WIFI_ZONE, ADMIN, REVENDEUR, AGENT, CLIENT
  tenant_id uuid references public.tenants(id),
  balance numeric default 0,
  is_active boolean default true,
  created_at timestamptz default now()
);

-- Table des Profils de Tickets (Forfaits)
create table public.ticket_profiles (
  id uuid default gen_random_uuid() primary key,
  tenant_id uuid references public.tenants(id) on delete cascade not null,
  name text not null,
  price numeric not null,
  created_at timestamptz default now()
);

-- Table des Tickets
create table public.tickets (
  id uuid default gen_random_uuid() primary key,
  tenant_id uuid references public.tenants(id) on delete cascade not null,
  profile_id uuid references public.ticket_profiles(id) not null,
  username text not null,
  password text,
  status text default 'NEUF', -- NEUF, VENDU, UTILISE, EXPIRE, ASSIGNE
  imported_at timestamptz default now(),
  sold_at timestamptz,
  sold_by uuid references public.users(id),
  assigned_to uuid references public.users(id)
);

-- Table Historique des Ventes
create table public.sales_history (
  id uuid default gen_random_uuid() primary key,
  tenant_id uuid references public.tenants(id) not null,
  seller_id uuid references public.users(id),
  ticket_id uuid references public.tickets(id),
  amount_paid numeric not null,
  sold_at timestamptz default now(),
  metadata jsonb
);

-- Table Zones WiFi
create table public.zones (
  id uuid default gen_random_uuid() primary key,
  tenant_id uuid references public.tenants(id) on delete cascade not null,
  name text not null,
  location text,
  is_active boolean default true,
  created_at timestamptz default now()
);

-- Table Paiements (Rechargement Revendeurs)
create table public.payments (
  id uuid default gen_random_uuid() primary key,
  tenant_id uuid references public.tenants(id) not null,
  reseller_id uuid references public.users(id),
  amount numeric not null,
  payment_method text, -- CASH, MOMO, OM
  phone_number text,
  created_by uuid references public.users(id),
  created_at timestamptz default now()
);

-- 2. Sécurité (Row Level Security - RLS)
-- Activez RLS sur toutes les tables
alter table public.tenants enable row level security;
alter table public.users enable row level security;
alter table public.ticket_profiles enable row level security;
alter table public.tickets enable row level security;
alter table public.sales_history enable row level security;
alter table public.zones enable row level security;
alter table public.payments enable row level security;

-- Création des politiques simplifiées (Pour le démarrage)
-- Note: En production, il faudrait affiner ces politiques pour isoler strictement les tenants.

-- Politique: Tout le monde peut lire (authentifié)
create policy "Enable read access for authenticated users" on public.tenants for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.users for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.ticket_profiles for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.tickets for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.sales_history for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.zones for select to authenticated using (true);
create policy "Enable read access for authenticated users" on public.payments for select to authenticated using (true);

-- Politique: Insert/Update/Delete pour les utilisateurs authentifiés
create policy "Enable write access for authenticated users" on public.tenants for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.users for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.ticket_profiles for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.tickets for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.sales_history for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.zones for all to authenticated using (true);
create policy "Enable write access for authenticated users" on public.payments for all to authenticated using (true);


-- 3. Fonctions et Triggers
-- Fonction pour créer automatiquement un user public lors de l'inscription Auth
create or replace function public.handle_new_user()
returns trigger as $$
begin
  insert into public.users (id, email, full_name, role, tenant_id)
  values (
    new.id, 
    new.email, 
    new.raw_user_meta_data->>'full_name',
    coalesce(new.raw_user_meta_data->>'role', 'CLIENT'),
    (new.raw_user_meta_data->>'tenant_id')::uuid
  );
  return new;
end;
$$ language plpgsql security definer;

-- Trigger pour l'inscription
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();

-- Fonction RPC: Créer une nouvelle agence (Utilisée dans CompleteSetup.tsx)
-- MISE A JOUR: La première agence devient ADMIN_GLOBAL
create or replace function create_new_agency(p_agency_name text)
returns void as $$
declare
  new_tenant_id uuid;
  is_first_agency boolean;
  user_role text;
  sub_status text;
begin
  -- Vérifier s'il existe déjà des agences dans la table tenants
  select not exists(select 1 from public.tenants) into is_first_agency;

  if is_first_agency then
    user_role := 'ADMIN_GLOBAL';
    sub_status := 'ACTIF'; -- Le super admin est actif par défaut
  else
    user_role := 'GESTIONNAIRE_WIFI_ZONE';
    sub_status := 'EN_ATTENTE';
  end if;

  -- 1. Créer le tenant
  insert into public.tenants (name, subscription_status)
  values (p_agency_name, sub_status)
  returning id into new_tenant_id;

  -- 2. Mettre à jour l'utilisateur courant
  update public.users
  set tenant_id = new_tenant_id,
      role = user_role
  where id = auth.uid();
end;
$$ language plpgsql security definer;

-- Fonction RPC: Supprimer complètement un tenant (Utilisée dans Agencies.tsx)
create or replace function delete_tenant_fully(target_tenant_id uuid)
returns void as $$
begin
  -- Vérifier que l'utilisateur est ADMIN_GLOBAL (sécurité basique)
  if not exists (select 1 from public.users where id = auth.uid() and role = 'ADMIN_GLOBAL') then
    raise exception 'Accès refusé';
  end if;

  -- Supprimer les données (Cascade s'occupe de la plupart, mais on nettoie users)
  delete from public.users where tenant_id = target_tenant_id;
  delete from public.tenants where id = target_tenant_id;
end;
$$ language plpgsql security definer;

-- Fonction RPC: Supprimer un utilisateur (Utilisée dans Users.tsx)
create or replace function delete_user_fully(target_user_id uuid)
returns void as $$
begin
  delete from public.users where id = target_user_id;
  -- Note: En théorie il faudrait aussi supprimer de auth.users via une Edge Function admin
  -- car Postgres standard ne peut pas écrire dans auth.users directement sans permissions superuser.
end;
$$ language plpgsql security definer;

