import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { CloudUpload, CheckCircle2, AlertTriangle, Loader2 } from 'lucide-react';
import { db } from '../services/db';

const Import: React.FC = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [file, setFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [profiles, setProfiles] = useState<any[]>([]);
  const [parsedData, setParsedData] = useState<any[]>([]);
  const [importSummary, setImportSummary] = useState({ success: 0, duplicates: 0 });
  const [tenantId, setTenantId] = useState<string>('');
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    db.auth.getUser().then(({ data: { user } }) => {
      if (user) db.from('users').select('tenant_id').eq('id', user.id).single().then(({ data }) => setTenantId(data?.tenant_id || ''));
    });
  }, []);

  const handleFile = (selectedFile: File) => {
    if (!selectedFile.name.endsWith('.csv')) { setError("Fichier CSV MikroTik uniquement (.csv)"); return; }
    setFile(selectedFile); setError(null);
  };

  const parseCSV = useCallback(() => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = (e.target?.result as string).replace(/^\uFEFF/, '');
      const lines = text.split('\n').filter(l => l.trim() !== '');
      const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/"/g, ''));
      const uIdx = headers.indexOf('username');
      if (uIdx === -1) { setError("Format invalide (colonne 'username' manquante)"); return; }
      const pIdx = headers.indexOf('password');
      const prIdx = headers.indexOf('profile');
      const tickets = lines.slice(1).map(l => {
        const c = l.split(',').map(col => col.trim().replace(/"/g, ''));
        return { username: c[uIdx], password: pIdx !== -1 ? c[pIdx] : '', profile: prIdx !== -1 ? (c[prIdx] || 'Standard') : 'Standard' };
      }).filter(t => t.username);
      setParsedData(tickets);
      const uniqueProfiles = Array.from(new Set(tickets.map(t => t.profile)));
      setProfiles(uniqueProfiles.map((p, i) => ({ id: i, name: p, price: '' })));
      setStep(2);
    };
    reader.readAsText(file);
  }, [file]);

  const runImport = async () => {
    if (profiles.some(p => !p.price)) { setError("Veuillez définir tous les prix."); return; }
    setIsSubmitting(true); setProgress(0);
    try {
      const profileMap: Record<string, string> = {};

      // 1. Création ou Récupération des IDs de profils
      for (const p of profiles) {
        const { data: existing } = await db.from('ticket_profiles')
            .select('id')
            .eq('tenant_id', tenantId)
            .eq('name', p.name)
            .maybeSingle();

        if (existing) { 
            profileMap[p.name] = existing.id; 
            await db.from('ticket_profiles').update({ price: Number(p.price) }).eq('id', existing.id); 
        } else { 
            // CORRECTION: Ajout de .select() pour retourner l'objet créé
            const { data: created, error: createError } = await db.from('ticket_profiles')
                .insert({ tenant_id: tenantId, name: p.name, price: Number(p.price) })
                .select()
                .single(); 

            if (createError) throw createError;
            if (created) profileMap[p.name] = created.id; 
        }
      }

      // 2. Préparation des données avec validation des IDs
      const payload = parsedData.map(t => {
          const profileId = profileMap[t.profile];
          if (!profileId) throw new Error(`Erreur technique: Impossible de récupérer l'ID pour le profil "${t.profile}". Réessayez.`);
          return { 
              tenant_id: tenantId, 
              profile_id: profileId, 
              username: t.username, 
              password: t.password, 
              status: 'NEUF' 
          };
      });

      // 3. Insertion par lots (Batch Insert)
      const BATCH_SIZE = 100;
      let totalSuccess = 0;
      let totalDupes = 0;
      for (let i = 0; i < payload.length; i += BATCH_SIZE) {
        const batch = payload.slice(i, i + BATCH_SIZE);
        const { data: existing } = await db.from('tickets').select('username').eq('tenant_id', tenantId).in('username', batch.map(b => b.username));
        const existingSet = new Set(existing?.map(e => e.username));
        const unique = batch.filter(b => !existingSet.has(b.username));
        if (unique.length > 0) { 
            const { error: insErr } = await db.from('tickets').insert(unique); 
            if (insErr) throw insErr; 
            totalSuccess += unique.length; 
        }
        totalDupes += (batch.length - unique.length);
        setProgress(Math.round(((i + batch.length) / payload.length) * 100));
      }
      setImportSummary({ success: totalSuccess, duplicates: totalDupes }); setStep(3);
    } catch (err: any) { setError(err.message); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="space-y-8 pb-32 animate-in fade-in duration-500">
      <header className="flex items-center gap-4"><div className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center shadow-lg"><CloudUpload /></div><h1 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Importation</h1></header>
      {error && <div className="p-5 bg-red-50 border border-red-100 rounded-3xl text-red-600 font-bold text-sm flex gap-3"><AlertTriangle /> {error}</div>}
      {step === 1 && (<div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 text-center space-y-8"><div className="border-4 border-dashed border-slate-100 rounded-[3rem] p-20 bg-slate-50/30 hover:bg-slate-50 transition-colors relative cursor-pointer group"><input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files?.[0] && handleFile(e.target.files[0])} accept=".csv" /><CloudUpload className="w-16 h-16 mx-auto mb-6 text-slate-200 group-hover:text-brand-600 transition-colors" /><p className="font-black text-slate-400 group-hover:text-slate-900">{file ? file.name : "Cliquez ou glissez votre CSV MikroTik ici"}</p></div>{file && <button onClick={parseCSV} className="w-full py-5 bg-brand-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Analyser le fichier</button>}</div>)}
      {step === 2 && (<div className="space-y-6"><div className="bg-white p-10 rounded-[3rem] border border-slate-100 space-y-8"><h3 className="font-black text-xl uppercase tracking-tight">Configuration des prix</h3><div className="space-y-4">{profiles.map(p => (<div key={p.id} className="flex items-center justify-between p-6 bg-slate-50 rounded-2xl border border-slate-100"><span className="font-black text-slate-700">{p.name}</span><input type="number" placeholder="Prix (ex: 2000)" value={p.price} onChange={e => setProfiles(prev => prev.map(x => x.id === p.id ? {...x, price: e.target.value} : x))} className="w-40 p-3 rounded-xl border border-slate-200 outline-none focus:ring-4 focus:ring-brand-50 font-black text-right" /></div>))}</div>{isSubmitting && <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden"><div className="h-full bg-brand-600 transition-all" style={{width: `${progress}%`}} /></div>}<button onClick={runImport} disabled={isSubmitting} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="animate-spin" /> : "Lancer l'importation"}</button></div></div>)}
      {step === 3 && (<div className="bg-white p-16 rounded-[4rem] border border-slate-100 text-center animate-in zoom-in-95"><CheckCircle2 className="w-24 h-24 text-emerald-500 mx-auto mb-8" /><h2 className="text-4xl font-black text-slate-900 mb-2">Importation Terminée</h2><div className="flex justify-center gap-8 py-10"><div><p className="text-3xl font-black text-emerald-600">{importSummary.success}</p><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Importés</p></div><div><p className="text-3xl font-black text-orange-600">{importSummary.duplicates}</p><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Doublons</p></div></div><button onClick={() => navigate('/stock')} className="bg-brand-600 text-white px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">Voir le stock</button></div>)}
    </div>
  );
};
export default Import;

import React, { useEffect, useState, useCallback } from 'react';
import { Users as UsersIcon, Ticket, Wallet, ShoppingCart, Loader2, RefreshCcw, TrendingUp, ArrowUpRight, ShieldCheck, Building2, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ revenue: 0, sold: 0, stock: 0, users: 0, pendingAgencies: 0, balance: 0 });
  const [recentSales, setRecentSales] = useState<any[]>([]);
  const [currentUserRole, setCurrentUserRole] = useState<UserRole | null>(null);

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;

      const { data: profile } = await db.from('users').select('role, tenant_id, balance').eq('id', user.id).maybeSingle();
      if (!profile) return;

      setCurrentUserRole(profile.role as UserRole);
      const isAdminGlobal = profile.role === UserRole.ADMIN_GLOBAL;
      const isReseller = profile.role === UserRole.REVENDEUR;
      const tId = profile.tenant_id;

      // Promesses de base
      let stockQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let soldQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let revQuery = db.from('sales_history').select('amount_paid');
      let userQuery = db.from('users').select('*', { count: 'exact', head: true });
      let salesQuery = db.from('sales_history').select('*, tickets(username, ticket_profiles(name))').order('sold_at', { ascending: false }).limit(6);

      // --- FILTRES SELON LE RÔLE ---
      if (isAdminGlobal) {
        // Pas de filtre tenant_id pour l'admin global
      } else if (isReseller) {
        // REVENDEUR : Uniquement ses données
        stockQuery = stockQuery.eq('assigned_to', user.id).eq('status', TicketStatus.ASSIGNE); // Stock dispo pour lui = ASSIGNÉ
        soldQuery = soldQuery.eq('sold_by', user.id).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('seller_id', user.id);
        salesQuery = salesQuery.eq('seller_id', user.id);
        // Le userQuery ne sert pas au revendeur (remplacé par Balance)
      } else {
        // ADMIN AGENCE : Données de toute l'agence
        stockQuery = stockQuery.eq('tenant_id', tId).eq('status', TicketStatus.NEUF);
        soldQuery = soldQuery.eq('tenant_id', tId).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('tenant_id', tId);
        userQuery = userQuery.eq('tenant_id', tId);
        salesQuery = salesQuery.eq('tenant_id', tId);
      }

      const promises = [
        stockQuery,
        soldQuery,
        revQuery,
        userQuery, // index 3
        salesQuery,
      ];

      if (isAdminGlobal) {
        promises.push(db.from('tenants').select('*', { count: 'exact', head: true }).eq('subscription_status', 'EN_ATTENTE'));
      }

      const results = await Promise.all(promises);
      const stockRes = results[0];
      const soldRes = results[1];
      const revRes = results[2];
      const userRes = results[3];
      const salesRes = results[4];
      const pendingRes = isAdminGlobal ? results[5] : { count: 0 };

      setStats({
        revenue: (revRes.data || []).reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0) || 0,
        sold: soldRes.count || 0,
        stock: stockRes.count || 0,
        users: userRes.count || 0,
        pendingAgencies: pendingRes.count || 0,
        balance: profile.balance || 0 // Utilisé pour le revendeur
      });
      setRecentSales(salesRes.data || []);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchDashboardData(); }, [fetchDashboardData]);

  if (loading) return <div className="h-[60vh] flex flex-col items-center justify-center"><Loader2 className="w-8 h-8 text-brand-600 animate-spin mb-4" /></div>;

  const isAdminGlobal = currentUserRole === UserRole.ADMIN_GLOBAL;
  const isReseller = currentUserRole === UserRole.REVENDEUR;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <div className="flex items-center gap-2 mb-2">
            {isAdminGlobal && <span className="bg-brand-50 text-brand-700 border border-brand-100 px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5 w-fit"><ShieldCheck className="w-3 h-3" /> Supervision</span>}
            {isReseller && <span className="bg-emerald-50 text-emerald-700 border border-emerald-100 px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5 w-fit"><Wallet className="w-3 h-3" /> Espace Revendeur</span>}
          </div>
          <h1 className="text-2xl font-bold text-slate-900 tracking-tight">
            {isAdminGlobal ? 'Vue d\'ensemble SaaS' : 'Tableau de Bord'}
          </h1>
          <p className="text-slate-500 text-sm">
            {isReseller ? 'Suivez vos ventes et votre stock personnel.' : 'Aperçu de votre activité commerciale en temps réel.'}
          </p>
        </div>
        <div className="flex items-center gap-3">
          {!isAdminGlobal && (
            <button onClick={() => navigate('/sales')} className="bg-brand-600 hover:bg-brand-700 text-white px-6 py-2.5 rounded-lg font-semibold text-sm flex items-center gap-2 shadow-sm transition-all active:scale-95"><ShoppingCart className="w-4 h-4" /> Nouvelle Vente</button>
          )}
          <button onClick={fetchDashboardData} className="p-2.5 bg-white border border-slate-200 rounded-lg text-slate-500 hover:text-brand-600 hover:border-brand-200 transition-all shadow-sm"><RefreshCcw className="w-4 h-4" /></button>
        </div>
      </header>

      {/* KPI GRID */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard label={isAdminGlobal ? "Revenu Global" : (isReseller ? "Vos Ventes (Total)" : "Chiffre d'Affaires")} value={`${stats.revenue.toLocaleString()}`} unit="GNF" icon={<Wallet />} color="text-brand-600" bg="bg-brand-50" />
        <StatCard label="Tickets Vendus" value={stats.sold} unit="Ventes" icon={<TrendingUp />} color="text-emerald-600" bg="bg-emerald-50" />
        {isAdminGlobal ? (
          <StatCard 
            label="Validations Requises" 
            value={stats.pendingAgencies} 
            unit="Agences" 
            icon={<Clock />} 
            color={stats.pendingAgencies > 0 ? "text-orange-600" : "text-slate-400"} 
            bg={stats.pendingAgencies > 0 ? "bg-orange-50" : "bg-slate-50"}
            onClick={() => stats.pendingAgencies > 0 && navigate('/agencies')}
            border={stats.pendingAgencies > 0}
          />
        ) : (
          <StatCard label={isReseller ? "Mon Stock (Assigné)" : "Stock Agence"} value={stats.stock} unit="Vouchers" icon={<Ticket />} color="text-indigo-600" bg="bg-indigo-50" />
        )}

        {/* Carte conditionnelle : Balance pour revendeur, Users pour Admin */}
        {isReseller ? (
             <StatCard label="Mon Solde (Prépayé)" value={stats.balance.toLocaleString()} unit="GNF" icon={<Wallet />} color={stats.balance < 50000 ? "text-red-600" : "text-emerald-600"} bg={stats.balance < 50000 ? "bg-red-50" : "bg-emerald-50"} border={stats.balance < 50000} />
        ) : (
             <StatCard label={isAdminGlobal ? "Utilisateurs Totaux" : "Utilisateurs"} value={stats.users} unit="Membres" icon={<UsersIcon />} color="text-slate-600" bg="bg-slate-100" />
        )}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 items-start">
        {/* Recent Transactions Table */}
        <div className="xl:col-span-2 bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between">
            <h3 className="font-semibold text-slate-900 text-sm">{isReseller ? 'Vos transactions récentes' : 'Transactions récentes'}</h3>
            <button onClick={() => navigate('/history')} className="text-xs font-medium text-brand-600 hover:text-brand-700 hover:underline">Voir tout</button>
          </div>
          <div className="divide-y divide-slate-50">
            {recentSales.length > 0 ? recentSales.map((sale, i) => (
              <div key={i} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-slate-50 rounded-lg flex items-center justify-center font-mono text-slate-500 text-xs border border-slate-100">
                    <Ticket className="w-4 h-4" />
                  </div>
                  <div>
                    <p className="font-semibold text-slate-900 text-sm">{sale.tickets?.username || 'Ticket Inconnu'}</p>
                    <p className="text-xs text-slate-500">{sale.tickets?.ticket_profiles?.name || 'Standard'}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-semibold text-slate-900 text-sm">{Number(sale.amount_paid).toLocaleString()} GNF</p>
                  <p className="text-[10px] font-medium text-slate-400 uppercase">{new Date(sale.sold_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
