                                     <input type="number" value={saasConfig.trial_period_days} onChange={e => setSaasConfig({...saasConfig, trial_period_days: Number(e.target.value)})} className="w-full pl-16 pr-6 py-5 rounded-[2rem] border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-black text-slate-900 text-xl transition-all" />
                                     <span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-400 uppercase">Jours</span>
                                 </div>
                             </div>
                         </div>

                         <div className="space-y-3">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Numéro Support Principal (WhatsApp)</label>
                             <div className="relative group">
                                 <Phone className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-emerald-600 transition-colors" />
                                 <input type="text" value={saasConfig.support_phone_number} onChange={e => setSaasConfig({...saasConfig, support_phone_number: e.target.value})} className="w-full pl-16 pr-6 py-5 rounded-[2rem] border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-emerald-50 outline-none font-black text-slate-900 text-lg transition-all" />
                             </div>
                         </div>

                         <div className="bg-orange-50 p-6 rounded-[2rem] border border-orange-100 flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-orange-500 shadow-sm"><AlertTriangle className="w-6 h-6" /></div>
                                <div>
                                    <p className="font-black text-slate-900 text-sm uppercase">Mode Maintenance</p>
                                    <p className="text-xs font-medium text-orange-700/70">Bloque l'accès à tous les gestionnaires.</p>
                                </div>
                            </div>
                            <button onClick={() => setSaasConfig({...saasConfig, is_maintenance_mode: !saasConfig.is_maintenance_mode})} className={`relative w-16 h-8 rounded-full transition-colors duration-300 ${saasConfig.is_maintenance_mode ? 'bg-orange-500' : 'bg-slate-300'}`}>
                                <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full shadow-md transition-transform duration-300 ${saasConfig.is_maintenance_mode ? 'translate-x-8' : 'translate-x-0'}`}></div>
                            </button>
                         </div>

                         <button onClick={handleSaveSaasConfig} disabled={saving} className="w-full py-6 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl transition-all active:scale-[0.98]">
                             {saving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-4 h-4" />}
                             ENREGISTRER LA CONFIGURATION
                         </button>
                     </div>
                 </div>

                 <div className="space-y-6">
                    <div className="bg-brand-50 p-10 rounded-[3rem] border border-brand-100 h-full flex flex-col justify-between">
                        <div>
                            <div className="flex items-center gap-3 mb-6 text-brand-700">
                                <ShieldCheck className="w-6 h-6" />
                                <h3 className="text-sm font-black uppercase tracking-widest">Admin Account</h3>
                            </div>
                            <div className="space-y-4">
                                <div className="bg-white p-5 rounded-[2rem] border border-brand-100/50 shadow-sm">
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Nom</p>
                                    <p className="font-bold text-slate-900">{userProfile?.full_name}</p>
                                </div>
                                <div className="bg-white p-5 rounded-[2rem] border border-brand-100/50 shadow-sm">
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Rôle</p>
                                    <p className="font-black text-brand-600 uppercase text-xs">SUPER ADMIN</p>
                                </div>
                            </div>
                        </div>
                        <button onClick={handleLogout} className="w-full mt-8 py-5 bg-white border-2 border-slate-50 text-slate-400 hover:text-red-500 hover:border-red-50 rounded-[2.5rem] font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 transition-all group">
                            <LogOut className="w-4 h-4 group-hover:translate-x-1 transition-transform" /> Se déconnecter
                        </button>
                    </div>
                 </div>
            </div>
        </div>
      ) : (
        /* ---------------------------------------------------------------------- */
        /* VIEW: MANAGERS & OTHERS */
        /* ---------------------------------------------------------------------- */
        <>
            <div className="bg-white p-4 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4"><div className="flex p-1.5 bg-slate-50 rounded-[2.5rem] w-full md:w-auto"><button onClick={() => setActiveTab('PROFILE')} className={`px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all flex items-center gap-3 ${activeTab === 'PROFILE' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}><UserCircle className="w-4 h-4" /> Mon Compte</button>{(userProfile?.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userProfile?.role === UserRole.ADMIN) && (<button onClick={() => setActiveTab('AGENCY')} className={`px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all flex items-center gap-3 ${activeTab === 'AGENCY' ? 'bg-white text-brand-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}><Building2 className="w-4 h-4" /> Agence</button>)}</div><div className="flex items-center gap-3 px-4"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Session :</span><span className="text-xs font-black text-slate-900">{userProfile?.role}</span></div></div>
            {activeTab === 'PROFILE' && (<div className="grid grid-cols-1 lg:grid-cols-3 gap-8"><div className="lg:col-span-2 bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-4 mb-8"><div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-2xl shadow-xl">{userProfile?.full_name?.charAt(0) || 'U'}</div><div><h2 className="text-2xl font-black text-slate-900 tracking-tight">{userProfile?.full_name}</h2><p className="text-slate-400 font-medium text-sm">{userProfile?.email}</p></div></div><form onSubmit={handleUpdateProfile} className="space-y-6 max-w-lg"><Input label="Nom Complet" icon={<UserCircle className="w-5 h-5" />} value={profileForm.fullName} onChange={(v: string) => setProfileForm({...profileForm, fullName: v})} /><div className="pt-6 border-t border-slate-50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Lock className="w-3 h-3" /> Sécurité</p><div className="grid grid-cols-1 md:grid-cols-2 gap-4"><Input label="Nouveau Mot de passe" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.newPassword} onChange={(v: string) => setProfileForm({...profileForm, newPassword: v})} /><Input label="Confirmer" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.confirmPassword} onChange={(v: string) => setProfileForm({...profileForm, confirmPassword: v})} /></div></div><button type="submit" disabled={saving} className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} METTRE À JOUR</button></form></div><div className="space-y-6"><button onClick={handleLogout} className="w-full py-5 bg-white border-2 border-slate-50 text-slate-400 hover:text-red-500 hover:border-red-50 rounded-[2.5rem] font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 transition-all group"><LogOut className="w-4 h-4 group-hover:translate-x-1 transition-transform" /> Se déconnecter</button></div></div>)}
            {activeTab === 'AGENCY' && (userProfile?.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userProfile?.role === UserRole.ADMIN) && (<div className="grid grid-cols-1 xl:grid-cols-3 gap-8 animate-in slide-in-from-right-4"><div className="xl:col-span-2 space-y-8"><div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-3 mb-8"><Store className="w-5 h-5 text-brand-600" /><h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">CONFIGURATION COMMERCIALE</h2></div><div className="space-y-6"><Input label="EN-TÊTE REÇU WHATSAPP" icon={<Smartphone className="w-5 h-5" />} value={agencyForm.whatsappHeader} onChange={(v: string) => setAgencyForm({...agencyForm, whatsappHeader: v})} /><div className="grid grid-cols-1 md:grid-cols-2 gap-8"><Input label="CONTACT SUPPORT CLIENT" icon={<Phone className="w-5 h-5" />} value={agencyForm.contactSupport} onChange={(v: string) => setAgencyForm({...agencyForm, contactSupport: v})} /><Input label="DEVISE" icon={<Banknote className="w-5 h-5" />} value={agencyForm.currency} onChange={(v: string) => setAgencyForm({...agencyForm, currency: v})} /></div><button onClick={handleSaveAgency} disabled={saving} className="w-full py-5 bg-brand-600 hover:bg-brand-700 text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} ENREGISTRER CONFIG</button></div></div></div><div className="space-y-8"><div className="bg-[#1e293b] p-10 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group"><div className="absolute top-0 right-0 w-40 h-40 bg-brand-500 rounded-full blur-[80px] opacity-20 -mr-10 -mt-10 group-hover:opacity-30 transition-opacity"></div><div className="flex items-center gap-3 mb-10 text-brand-300 relative z-10"><Sparkles className="w-5 h-5" /><h2 className="text-sm font-black uppercase tracking-widest">STOCK LIVE</h2></div><div className="bg-white/5 border border-white/10 rounded-3xl p-6 mb-8 relative z-10"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">TOTAL VOUCHERS</p><p className="text-5xl font-black text-white tracking-tighter">{stockCount}</p></div><button onClick={handleCleanExpired} className="w-full py-4 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-2xl font-black text-[10px] tracking-widest uppercase flex items-center justify-center gap-2 transition-all"><Trash2 className="w-4 h-4" /> NETTOYER {expiredCount} EXPIRÉS</button></div></div></div>)}
        </>
      )}
    </div>
  );
};
const Input = ({ label, icon, value, onChange, type = "text" }: any) => (<div className="space-y-3 text-left"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{label}</label><div className="relative group"><div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-600 transition-colors">{icon}</div><input type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all" /></div></div>);
export default Settings;

import React, { useEffect, useState, useCallback } from 'react';
import { UserPlus, Mail, Users as UsersIcon, User as UserIcon, Pencil, Loader2, ShieldCheck, Trash2, Search, Crown, CircleDollarSign, MoreHorizontal, Wallet, CheckCircle2, AlertTriangle, Building2 } from 'lucide-react';
import { createClient } from '@supabase/supabase-js';
import { db, supabaseUrl, supabaseKey } from '../services/db';
import { UserRole, User, TicketStatus } from '../types';

const Users: React.FC = () => {
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [roleFilter, setRoleFilter] = useState<'ALL' | UserRole.REVENDEUR | UserRole.AGENT | 'ADMIN'>('ALL');
  const [currentUserProfile, setCurrentUserProfile] = useState<any>(null);
  const [showModal, setShowModal] = useState(false);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);
  const [confirmDeleteText, setConfirmDeleteText] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [formData, setFormData] = useState({ fullName: '', email: '', password: '', role: UserRole.REVENDEUR });

  const notify = useCallback((type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 5000); }, []);

  const fetchData = useCallback(async () => {
    try {
      setLoading(true);
      const { data: { user: authUser } } = await db.auth.getUser();
      if (!authUser) return;
      const { data: profile } = await db.from('users').select('*').eq('id', authUser.id).single();
      if (!profile) throw new Error("Profil introuvable.");
      setCurrentUserProfile(profile);

      // Récupération des utilisateurs avec leur agence et historique des ventes
      let query = db.from('users').select('*, tenants(name), sales_history(amount_paid)');

      // Si pas ADMIN_GLOBAL, on filtre par tenant_id
      if (profile.role !== UserRole.ADMIN_GLOBAL) query = query.eq('tenant_id', profile.tenant_id);

      const { data, error } = await query.eq('is_active', true).order('created_at', { ascending: false });
      if (error) throw error;

      setUsers((data || []).map((u: any) => ({ ...u, total_revenue: u.sales_history?.reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0) || 0 })));
    } catch (err: any) { notify('error', err.message); } finally { setLoading(false); }
  }, [notify]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleHardDelete = async () => {
    if (!userToDelete || confirmDeleteText !== 'SUPPRIMER') return;
    setIsDeleting(true);
    try {
      await db.from('tickets').update({ status: TicketStatus.NEUF, assigned_to: null }).eq('assigned_to', userToDelete.id).eq('status', TicketStatus.ASSIGNE);
      const { error: rpcError } = await db.rpc('delete_user_fully', { target_user_id: userToDelete.id });
      if (rpcError) throw rpcError;
      notify('success', `Membre ${userToDelete.full_name} retiré.`); setUsers(prev => prev.filter(u => u.id !== userToDelete.id)); setUserToDelete(null); setConfirmDeleteText('');
    } catch (err: any) { notify('error', "Erreur : " + err.message); } finally { setIsDeleting(false); }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting || !currentUserProfile) return;
    setIsSubmitting(true);
    try {
      if (editingUser) {
        const { error } = await db.from('users').update({ full_name: formData.fullName.trim(), role: formData.role }).eq('id', editingUser.id);
        if (error) throw error; notify('success', `Profil mis à jour.`);
      } else {
        // IMPORTANT: Création d'un client secondaire pour ne pas écraser la session de l'admin actuel
        const tempClient = createClient(supabaseUrl, supabaseKey);

        const { error: authError } = await tempClient.auth.signUp({ 
            email: formData.email.trim().toLowerCase(), 
            password: formData.password, 
            options: { 
                data: { 
                    full_name: formData.fullName.trim(), 
                    tenant_id: currentUserProfile.tenant_id, 
                    role: formData.role 
                } 
            } 
        });
        if (authError) throw authError; 
        notify('success', "Nouveau membre ajouté.");
      }
      await fetchData(); setShowModal(false); setFormData({ fullName: '', email: '', password: '', role: UserRole.REVENDEUR }); setEditingUser(null);
    } catch (err: any) { notify('error', err.message); } finally { setIsSubmitting(false); }
  };

  const getRoleInfo = (role: string) => { switch(role) { case UserRole.ADMIN_GLOBAL: return { label: 'SaaS Master', color: 'bg-red-50 text-red-700 border-red-100', icon: ShieldCheck }; case UserRole.GESTIONNAIRE_WIFI_ZONE: case UserRole.ADMIN: return { label: 'Administrateur', color: 'bg-slate-900 text-white border-slate-700', icon: Crown }; case UserRole.REVENDEUR: return { label: 'Revendeur', color: 'bg-emerald-50 text-emerald-700 border-emerald-100', icon: CircleDollarSign }; default: return { label: 'Agent', color: 'bg-indigo-50 text-indigo-700 border-indigo-100', icon: UserIcon }; } };
  const filteredUsers = users.filter(u => { const matchesSearch = u.full_name.toLowerCase().includes(searchTerm.toLowerCase()) || u.email.toLowerCase().includes(searchTerm.toLowerCase()); const matchesRole = roleFilter === 'ALL' ? true : roleFilter === 'ADMIN' ? (u.role === UserRole.GESTIONNAIRE_WIFI_ZONE || u.role === UserRole.ADMIN) : u.role === roleFilter; return matchesSearch && matchesRole; });

  return (
    <div className="space-y-8 pb-32 animate-in fade-in duration-500">
      {toast && (<div className={`fixed top-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-right ${toast.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}><CheckCircle2 className="w-5 h-5" /><p className="font-bold text-sm">{toast.message}</p></div>)}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6"><div><div className="flex items-center gap-2 text-indigo-600 mb-2"><UsersIcon className="w-5 h-5" /><span className="text-[10px] font-black uppercase tracking-widest">Gestion d'équipe</span></div><h1 className="text-4xl font-black text-slate-900 tracking-tight">Membres & Accès</h1><p className="text-slate-400 font-medium mt-1">Administrez les rôles et les permissions de votre agence.</p></div><button onClick={() => { setEditingUser(null); setFormData({fullName: '', email: '', password: '', role: UserRole.REVENDEUR}); setShowModal(true); }} className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-xl shadow-indigo-200 transition-all active:scale-95"><UserPlus className="w-4 h-4" /> Nouveau Membre</button></div>
      <div className="bg-white p-2 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col md:flex-row gap-2"><div className="relative flex-1"><Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" /><input type="text" placeholder="Rechercher par nom ou email..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full h-full pl-14 pr-6 py-4 bg-transparent rounded-[2rem] font-bold text-slate-700 placeholder:text-slate-300 outline-none" /></div><div className="flex bg-slate-50 p-1.5 rounded-[2rem]">{[{ id: 'ALL', label: 'Tous' }, { id: UserRole.REVENDEUR, label: 'Revendeurs' }, { id: UserRole.AGENT, label: 'Agents' }, { id: 'ADMIN', label: 'Admins' }].map((tab) => (<button key={tab.id} onClick={() => setRoleFilter(tab.id as any)} className={`px-6 py-3 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${roleFilter === tab.id ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>{tab.label}</button>))}</div></div>
      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden min-h-[400px]"><div className="overflow-x-auto"><table className="w-full text-left"><thead><tr className="border-b border-slate-50 bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest"><th className="px-10 py-6">MEMBRE</th>{currentUserProfile?.role === UserRole.ADMIN_GLOBAL && <th className="px-10 py-6">AGENCE</th>}<th className="px-10 py-6">RÔLE</th><th className="px-10 py-6">PERFORMANCE</th><th className="px-10 py-6">SOLDE</th><th className="px-10 py-6 text-right">ACTIONS</th></tr></thead><tbody className="divide-y divide-slate-50">{loading ? (<tr><td colSpan={currentUserProfile?.role === UserRole.ADMIN_GLOBAL ? 6 : 5} className="py-20 text-center"><Loader2 className="w-10 h-10 animate-spin text-indigo-200 mx-auto" /></td></tr>) : filteredUsers.length === 0 ? (<tr><td colSpan={currentUserProfile?.role === UserRole.ADMIN_GLOBAL ? 6 : 5} className="py-20 text-center text-slate-300 font-bold uppercase text-xs tracking-widest">Aucun membre trouvé</td></tr>) : filteredUsers.map((user) => { const role = getRoleInfo(user.role); const RoleIcon = role.icon; return (<tr key={user.id} className="group hover:bg-indigo-50/30 transition-colors"><td className="px-10 py-6"><div className="flex items-center gap-4"><div className="w-12 h-12 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-500 font-black text-lg shadow-inner group-hover:bg-white group-hover:scale-110 transition-all">{user.full_name.charAt(0)}</div><div><p className="font-black text-slate-900 text-sm">{user.full_name}</p><div className="flex items-center gap-1.5 text-slate-400 mt-0.5"><Mail className="w-3 h-3" /><p className="text-[10px] font-bold truncate max-w-[150px]">{user.email}</p></div></div></div></td>{currentUserProfile?.role === UserRole.ADMIN_GLOBAL && (<td className="px-10 py-6"><div className="flex items-center gap-2"><Building2 className="w-4 h-4 text-slate-300" /><span className="text-xs font-bold text-slate-600 uppercase">{(user.tenants as any)?.name || 'N/A'}</span></div></td>)}<td className="px-10 py-6"><div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl border ${role.color}`}><RoleIcon className="w-3.5 h-3.5" /><span className="text-[9px] font-black uppercase tracking-wide">{role.label}</span></div></td><td className="px-10 py-6"><div className="flex flex-col"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Chiffre d'affaires</span><span className="text-sm font-black text-slate-900">{user.total_revenue.toLocaleString()} GNF</span></div></td><td className="px-10 py-6">{user.role === UserRole.REVENDEUR ? (<div className="flex items-center gap-2"><Wallet className={`w-4 h-4 ${user.balance < 0 ? 'text-red-500' : 'text-emerald-500'}`} /><span className={`text-sm font-black ${user.balance < 0 ? 'text-red-500' : 'text-emerald-600'}`}>{user.balance?.toLocaleString() || 0}</span></div>) : (<span className="text-slate-300">-</span>)}</td><td className="px-10 py-6 text-right"><div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity"><button onClick={() => { setEditingUser(user); setFormData({fullName: user.full_name, email: user.email, password:'', role: user.role}); setShowModal(true); }} className="p-2.5 rounded-xl bg-white border border-slate-100 text-slate-400 hover:text-indigo-600 hover:border-indigo-100 transition-all shadow-sm"><Pencil className="w-4 h-4" /></button>{user.id !== currentUserProfile?.id && (<button onClick={() => setUserToDelete(user)} className="p-2.5 rounded-xl bg-white border border-slate-100 text-slate-400 hover:text-red-600 hover:border-red-100 transition-all shadow-sm"><Trash2 className="w-4 h-4" /></button>)}</div></td></tr>); })}</tbody></table></div></div>
      {showModal && (<div className="fixed inset-0 z-50 flex items-center justify-center p-6"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setShowModal(false)} /><form onSubmit={handleSubmit} className="bg-white w-full max-w-md rounded-[3.5rem] p-12 relative z-10 animate-in zoom-in-95 shadow-2xl border border-slate-100"><h2 className="text-2xl font-black mb-10 uppercase text-slate-900 text-center tracking-tight">{editingUser ? 'Modifier Profil' : 'Nouveau Membre'}</h2><div className="space-y-5"><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Identité</label><input type="text" required value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} placeholder="Nom Complet" className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-50 transition-all" /></div>{!editingUser && (<><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Accès</label><input type="email" required value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} placeholder="Email professionnel" className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-50 transition-all" /><input type="password" required value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} placeholder="Mot de passe provisoire" className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-50 transition-all" /></div></>)}<div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Rôle Système</label><div className="relative"><select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as UserRole})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 outline-none appearance-none cursor-pointer focus:ring-4 focus:ring-indigo-50 transition-all"><option value={UserRole.REVENDEUR}>REVENDEUR (Prépayé)</option><option value={UserRole.AGENT}>AGENT TERRAIN (Vente Directe)</option><option value={UserRole.ASSOCIE}>ADMINISTRATEUR (Gestion)</option></select><MoreHorizontal className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none w-5 h-5" /></div></div></div><button type="submit" disabled={isSubmitting} className="w-full mt-10 py-6 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] shadow-xl transition-all transform active:scale-95 flex items-center justify-center gap-3">{isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : "ENREGISTRER LE MEMBRE"}</button><button type="button" onClick={() => setShowModal(false)} className="w-full mt-3 py-4 text-slate-400 hover:text-slate-600 font-bold text-xs uppercase tracking-widest transition-colors">Annuler</button></form></div>)}
      {userToDelete && (<div className="fixed inset-0 z-[100] flex items-center justify-center p-6"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setUserToDelete(null)} /><div className="bg-white w-full max-w-sm rounded-[3rem] p-10 text-center relative z-10 border-t-8 border-red-600 shadow-2xl animate-in zoom-in-95"><div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner"><AlertTriangle className="w-10 h-10" /></div><h3 className="text-xl font-black text-slate-900 mb-2 uppercase">Supprimer le compte ?</h3><p className="text-slate-500 text-sm mb-8 leading-relaxed px-4">Cette action supprimera définitivement l'accès de <strong>{userToDelete.full_name}</strong>.</p><div className="space-y-4"><input type="text" value={confirmDeleteText} onChange={e => setConfirmDeleteText(e.target.value)} placeholder="Taper SUPPRIMER" className="w-full p-4 border-2 border-red-50 bg-red-50/50 rounded-2xl text-center font-black uppercase outline-none focus:border-red-200 focus:bg-white transition-all text-red-900 placeholder:text-red-200" /><button onClick={handleHardDelete} disabled={isDeleting || confirmDeleteText !== 'SUPPRIMER'} className="w-full py-5 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-red-100 transition-all">{isDeleting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "CONFIRMER"}</button><button onClick={() => setUserToDelete(null)} className="w-full py-4 text-slate-400 hover:text-slate-900 font-bold text-xs uppercase tracking-widest transition-colors">Annuler</button></div></div></div>)}
    </div>
  );
};
export default Users;

import React, { useEffect, useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { LayoutDashboard, ShoppingCart, CloudUpload, Ticket, History, Users, LogOut, Wallet, Settings, Building2, Zap, ChevronLeft, MapPin, Tag } from 'lucide-react';
import { NavItem, UserRole } from '../types.ts';
import { db } from '../services/db.ts';

interface SidebarProps { isOpen: boolean; setIsOpen: (isOpen: boolean) => void; }

const Sidebar: React.FC<SidebarProps> = ({ isOpen, setIsOpen }) => {
  const navigate = useNavigate();
  const [userInfo, setUserInfo] = useState<{ role: UserRole | null; fullName: string; agencyName: string; }>({ role: null, fullName: '', agencyName: '' });

  useEffect(() => {
    const getProfile = async () => {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data } = await db.from('users').select('role, full_name, tenants(name)').eq('id', user.id).maybeSingle();
        if (data) setUserInfo({ role: data.role as UserRole, fullName: data.full_name || 'Utilisateur', agencyName: (data.tenants as any)?.name || 'Hotspot Cloud' });
      }
    };
    getProfile();
  }, []);

  const handleLogout = async () => { await db.auth.signOut(); window.location.href = '/'; };

  const navItems: NavItem[] = [
    { label: 'Tableau de bord', path: '/dashboard', icon: LayoutDashboard },
    { label: 'Guichet Vente', path: '/sales', icon: ShoppingCart },
    { label: 'Import CSV', path: '/import', icon: CloudUpload },
    { label: 'Gestion Stock', path: '/stock', icon: Ticket },
    { label: 'Historique', path: '/history', icon: History },
    { label: 'Zones WiFi', path: '/zones', icon: MapPin },
    { label: 'Forfaits', path: '/profiles', icon: Tag },
    { label: 'Revendeurs', path: '/resellers', icon: Wallet },
    { label: 'Utilisateurs', path: '/users', icon: Users },
    { label: 'Agences SaaS', path: '/agencies', icon: Building2 },
    { label: 'Abonnements', path: '/subscriptions', icon: Zap },
    { label: 'Paramètres', path: '/settings', icon: Settings },
  ];

  const filteredItems = navItems.filter(item => {
    if (userInfo.role === UserRole.ADMIN_GLOBAL) return !['/sales', '/profiles', '/import', '/zones'].includes(item.path);
    if (userInfo.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userInfo.role === UserRole.ADMIN) return !['/agencies', '/subscriptions'].includes(item.path);
    if (userInfo.role === UserRole.REVENDEUR) return ['/dashboard', '/sales', '/history', '/stock'].includes(item.path);
    return ['/dashboard', '/sales', '/stock', '/history'].includes(item.path);
  });

  return (
    <>
      {isOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] md:hidden animate-in fade-in" onClick={() => setIsOpen(false)} />}
      <aside className={`fixed md:sticky top-0 left-0 z-[70] h-screen w-72 bg-white border-r border-slate-200 transition-transform duration-300 ease-in-out flex flex-col ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>

        {/* Header Branding */}
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => navigate('/dashboard')}>
                <div className="w-9 h-9 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold text-lg shadow-sm">
                  {userInfo.agencyName.charAt(0)}
                </div>
                <div className="flex flex-col">
                  <span className="font-bold text-slate-900 text-sm leading-tight tracking-tight">Hotspot<span className="text-brand-600">Pro</span></span>
                  <span className="text-[10px] font-medium text-slate-400 uppercase tracking-wide">Enterprise</span>
                </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="md:hidden p-2 text-slate-400 hover:text-slate-700"><ChevronLeft className="w-5 h-5" /></button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto px-4 py-6 space-y-0.5 custom-scrollbar">
          {filteredItems.map((item) => (
            <NavLink 
              key={item.path} 
              to={item.path} 
              onClick={() => setIsOpen(false)} 
              className={({ isActive }) => `flex items-center gap-3 px-4 py-2.5 rounded-lg transition-all text-sm font-medium ${isActive ? 'bg-brand-50 text-brand-700' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'}`}
            >
              <item.icon className={`w-4 h-4 ${ ({ isActive }:any) => isActive ? 'text-brand-600' : 'text-slate-400'}`} />
              <span>{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* User Profile Footer */}
        <div className="p-4 border-t border-slate-100">
           <div className="flex items-center gap-3 px-2">
              <div className="w-8 h-8 bg-slate-100 rounded-full flex items-center justify-center text-slate-600 font-bold text-xs border border-slate-200">
                {userInfo.fullName.charAt(0)}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-slate-900 truncate">{userInfo.fullName}</p>
                <p className="text-[10px] text-slate-500 truncate capitalize">{userInfo.role?.replace(/_/g, ' ').toLowerCase()}</p>
              </div>
              <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="Déconnexion">
                <LogOut className="w-4 h-4" />
              </button>
           </div>
        </div>
      </aside>
    </>
  );
};
export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Search, CloudUpload, Trash2, Loader2, AlertCircle, AlertTriangle, CheckCircle2, Building2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Stock: React.FC = () => {
  const navigate = useNavigate();
  const [filter, setFilter] = useState<'TOUS' | 'NEUF' | 'VENDU'>('TOUS');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [search, setSearch] = useState('');
  const [tickets, setTickets] = useState<any[]>([]);
  const [agencies, setAgencies] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [ticketToDelete, setTicketToDelete] = useState<any | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  useEffect(() => { fetchInitialData(); }, []);
  useEffect(() => { fetchStock(); }, [filter, search, agencyFilter, currentUser]);

  const fetchInitialData = async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: userData } = await db.from('users').select('role, tenant_id, id').eq('id', user.id).single();
        if (userData) {
          setCurrentUser(userData);
          if (userData.role === UserRole.ADMIN_GLOBAL) {
            const { data: tData } = await db.from('tenants').select('id, name').order('name');
            setAgencies(tData || []);
          }
        }
      }
    } catch (err) { console.error(err); }
  };

  const fetchStock = async () => {
    if (!currentUser) return;
    try {
      setLoading(true);
      let query = db.from('tickets').select(`id, username, password, status, imported_at, tenants(name), ticket_profiles(name, price)`).order('imported_at', { ascending: false });

      const isReseller = currentUser.role === UserRole.REVENDEUR;

      // 1. Restriction de base
      if (currentUser.role === UserRole.ADMIN_GLOBAL) { 
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); 
      } else { 
        query = query.eq('tenant_id', currentUser.tenant_id); 
      }

      if (isReseller) {
         // Le revendeur ne voit QUE ce qui lui est assigné
         query = query.eq('assigned_to', currentUser.id);
      }

      // 2. Filtres de statut
      if (filter !== 'TOUS') {
          if (isReseller && filter === 'NEUF') {
              // Pour un revendeur, "NEUF" visuellement = "ASSIGNÉ" en BDD
              query = query.eq('status', TicketStatus.ASSIGNE);
          } else {
              query = query.eq('status', filter);
          }
      }

      if (search) query = query.ilike('username', `%${search}%`);

      const { data, error: tError } = await query.limit(300);
      if (tError) throw tError;
      setTickets(data || []);
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  };

  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 3000); };

  const handleVerifyDelete = (ticket: any) => { 
    if (currentUser?.role === UserRole.REVENDEUR) { showToast('error', "Action refusée."); return; } 
    if (ticket.status !== TicketStatus.NEUF) { showToast('error', "Impossible de supprimer un ticket vendu ou assigné."); return; } 
    setTicketToDelete(ticket); 
  };

  const performDelete = async () => { 
    if (!ticketToDelete) return; 
    setIsDeleting(true); 
    try { 
        const { error: dError } = await db.from('tickets').delete().eq('id', ticketToDelete.id); 
        if (dError) throw dError; 
        setTickets(prev => prev.filter(t => t.id !== ticketToDelete.id)); 
        showToast('success', `Ticket supprimé.`); 
        setTicketToDelete(null); 
    } catch (err: any) { 
        showToast('error', err.message); 
    } finally { 
        setIsDeleting(false); 
    } 
  };

  const isReseller = currentUser?.role === UserRole.REVENDEUR;

  return (
    <div className="space-y-8 font-sans pb-20 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4"><div><span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1 block">{currentUser?.role === UserRole.ADMIN_GLOBAL ? 'SUPERVISION GLOBALE DES STOCKS' : (isReseller ? 'MON STOCK PERSONNEL' : 'INVENTAIRE AGENCE')}</span><h1 className="text-4xl font-black text-[#1e293b] tracking-tight">Gestion Stock</h1></div>{currentUser?.role === UserRole.GESTIONNAIRE_WIFI_ZONE && (<button onClick={() => navigate('/import')} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black text-xs tracking-widest uppercase shadow-xl flex items-center gap-3 hover:bg-black transition-all"><CloudUpload className="w-4 h-4" /> IMPORTER CSV</button>)}</div>
      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden"><div className="p-8 space-y-6"><div className="flex flex-col md:flex-row gap-4"><div className="relative group flex-1"><Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-500 transition-colors" /><input type="text" placeholder="Rechercher par code..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-14 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50/30 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none font-bold text-slate-600 transition-all" /></div>{currentUser?.role === UserRole.ADMIN_GLOBAL && (<div className="relative w-full md:w-64"><Building2 className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" /><select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all"><option value="ALL">Toutes les agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>)}</div><div className="flex gap-3">{(['TOUS', 'NEUF', 'VENDU'] as const).map((f) => (<button key={f} onClick={() => setFilter(f)} className={`px-6 py-2 rounded-xl font-black text-[10px] tracking-widest uppercase transition-all ${filter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border border-slate-100 text-slate-400 hover:text-slate-600'}`}>{f === 'NEUF' ? 'STOCK DISPO' : f}</button>))}</div></div><div className="overflow-x-auto"><table className="w-full text-left border-collapse"><thead><tr className="border-y border-slate-50 bg-slate-50/30 text-[10px] font-black text-slate-400 uppercase tracking-widest"><th className="px-8 py-4">CODE</th>{(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && <th className="px-8 py-4">AGENCE</th>}<th className="px-8 py-4">PROFIL</th><th className="px-8 py-4 text-right">PRIX</th><th className="px-8 py-4 text-center">STATUT</th>{currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && <th className="px-8 py-4 text-right">ACTIONS</th>}</tr></thead><tbody className="divide-y divide-slate-50">{loading ? (<tr><td colSpan={6} className="px-8 py-20 text-center"><Loader2 className="w-8 h-8 animate-spin mx-auto text-indigo-200" /></td></tr>) : tickets.length === 0 ? (<tr><td colSpan={6} className="px-8 py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun ticket</td></tr>) : tickets.map((item) => {
        let statusLabel = 'VENDU';
        let statusColor = 'bg-emerald-50 text-emerald-500';

        if (item.status === TicketStatus.NEUF) {
            statusLabel = 'EN STOCK';
            statusColor = 'bg-indigo-50 text-indigo-500';
        } else if (item.status === TicketStatus.ASSIGNE) {
            if (isReseller) {
                statusLabel = 'EN STOCK';
                statusColor = 'bg-indigo-50 text-indigo-500';
            } else {
                statusLabel = 'ASSIGNÉ';
                statusColor = 'bg-purple-50 text-purple-600';
            }
        }

        return (
          <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
            <td className="px-8 py-6 font-black text-slate-900 tracking-tight">{item.username}</td>
            {(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && (<td className="px-8 py-6"><div className="flex items-center gap-2"><Building2 className="w-3 h-3 text-slate-300" /><span className="text-[10px] font-black text-slate-500 uppercase">{item.tenants?.name}</span></div></td>)}
            <td className="px-8 py-6 font-black text-xs text-indigo-500 uppercase">{item.ticket_profiles?.name}</td>
            <td className="px-8 py-6 font-black text-slate-900 text-right">{Number(item.ticket_profiles?.price).toLocaleString()} GNF</td>
            <td className="px-8 py-6 text-center"><span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusColor}`}>{statusLabel}</span></td>
            {currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && (<td className="px-8 py-6 text-right"><button onClick={() => handleVerifyDelete(item)} disabled={item.status === TicketStatus.VENDU || item.status === TicketStatus.ASSIGNE} className={`p-2 rounded-lg transition-all ${(item.status === TicketStatus.VENDU || item.status === TicketStatus.ASSIGNE) ? 'text-slate-100 opacity-20' : 'text-slate-300 hover:text-red-600 hover:bg-red-50'}`}><Trash2 className="w-4 h-4" /></button></td>)}
          </tr>
        );
      })}</tbody></table></div></div>
      {ticketToDelete && (<div className="fixed inset-0 z-50 flex items-center justify-center p-4"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isDeleting && setTicketToDelete(null)} /><div className="bg-white w-full max-w-sm rounded-[3rem] p-10 text-center relative z-10 animate-in zoom-in-95 shadow-2xl"><div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6"><AlertTriangle className="w-10 h-10" /></div><h3 className="text-2xl font-black text-slate-900 mb-2 uppercase">Supprimer ?</h3><p className="text-slate-500 text-sm mb-8">Action irréversible sur le ticket <strong>{ticketToDelete.username}</strong>.</p><div className="space-y-3"><button onClick={performDelete} disabled={isDeleting} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-red-700">{isDeleting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "OUI, SUPPRIMER"}</button><button onClick={() => setTicketToDelete(null)} className="w-full py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-xs uppercase">ANNULER</button></div></div></div>)}
    </div>
  );
};
export default Stock;

import React, { useState, useEffect } from 'react';
import { Search, CloudUpload, Trash2, Loader2, AlertCircle, AlertTriangle, CheckCircle2, Building2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Stock: React.FC = () => {
  const navigate = useNavigate();
  const [filter, setFilter] = useState<'TOUS' | 'NEUF' | 'VENDU'>('TOUS');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [search, setSearch] = useState('');
  const [tickets, setTickets] = useState<any[]>([]);
  const [agencies, setAgencies] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [ticketToDelete, setTicketToDelete] = useState<any | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  useEffect(() => { fetchInitialData(); }, []);
  useEffect(() => { fetchStock(); }, [filter, search, agencyFilter, currentUser]);

  const fetchInitialData = async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: userData } = await db.from('users').select('role, tenant_id, id').eq('id', user.id).single();
        if (userData) {
          setCurrentUser(userData);
          if (userData.role === UserRole.ADMIN_GLOBAL) {
            const { data: tData } = await db.from('tenants').select('id, name').order('name');
            setAgencies(tData || []);
          }
        }
      }
    } catch (err) { console.error(err); }
  };

  const fetchStock = async () => {
    if (!currentUser) return;
    try {
      setLoading(true);
      let query = db.from('tickets').select(`id, username, password, status, imported_at, tenants(name), ticket_profiles(name, price)`).order('imported_at', { ascending: false });

      const isReseller = currentUser.role === UserRole.REVENDEUR;

      // 1. Restriction de base
      if (currentUser.role === UserRole.ADMIN_GLOBAL) { 
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); 
      } else { 
        query = query.eq('tenant_id', currentUser.tenant_id); 
      }

      if (isReseller) {
         // Le revendeur ne voit QUE ce qui lui est assigné
         query = query.eq('assigned_to', currentUser.id);
      }

      // 2. Filtres de statut
      if (filter !== 'TOUS') {
          if (isReseller && filter === 'NEUF') {
              // Pour un revendeur, "NEUF" visuellement = "ASSIGNÉ" en BDD
              query = query.eq('status', TicketStatus.ASSIGNE);
          } else {
              query = query.eq('status', filter);
          }
      }

      if (search) query = query.ilike('username', `%${search}%`);

      const { data, error: tError } = await query.limit(300);
      if (tError) throw tError;
      setTickets(data || []);
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  };

  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 3000); };

  const handleVerifyDelete = (ticket: any) => { 
    if (currentUser?.role === UserRole.REVENDEUR) { showToast('error', "Action refusée."); return; } 
    if (ticket.status !== TicketStatus.NEUF) { showToast('error', "Impossible de supprimer un ticket vendu ou assigné."); return; } 
    setTicketToDelete(ticket); 
  };

  const performDelete = async () => { 
    if (!ticketToDelete) return; 
    setIsDeleting(true); 
    try { 
        const { error: dError } = await db.from('tickets').delete().eq('id', ticketToDelete.id); 
        if (dError) throw dError; 
        setTickets(prev => prev.filter(t => t.id !== ticketToDelete.id)); 
        showToast('success', `Ticket supprimé.`); 
        setTicketToDelete(null); 
    } catch (err: any) { 
        showToast('error', err.message); 
    } finally { 
        setIsDeleting(false); 
    } 
  };

  const isReseller = currentUser?.role === UserRole.REVENDEUR;

  return (
    <div className="space-y-8 font-sans pb-20 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4"><div><span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1 block">{currentUser?.role === UserRole.ADMIN_GLOBAL ? 'SUPERVISION GLOBALE DES STOCKS' : (isReseller ? 'MON STOCK PERSONNEL' : 'INVENTAIRE AGENCE')}</span><h1 className="text-4xl font-black text-[#1e293b] tracking-tight">Gestion Stock</h1></div>{currentUser?.role === UserRole.GESTIONNAIRE_WIFI_ZONE && (<button onClick={() => navigate('/import')} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black text-xs tracking-widest uppercase shadow-xl flex items-center gap-3 hover:bg-black transition-all"><CloudUpload className="w-4 h-4" /> IMPORTER CSV</button>)}</div>
      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden"><div className="p-8 space-y-6"><div className="flex flex-col md:flex-row gap-4"><div className="relative group flex-1"><Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-500 transition-colors" /><input type="text" placeholder="Rechercher par code..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-14 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50/30 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none font-bold text-slate-600 transition-all" /></div>{currentUser?.role === UserRole.ADMIN_GLOBAL && (<div className="relative w-full md:w-64"><Building2 className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" /><select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all"><option value="ALL">Toutes les agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select></div>)}</div><div className="flex gap-3">{(['TOUS', 'NEUF', 'VENDU'] as const).map((f) => (<button key={f} onClick={() => setFilter(f)} className={`px-6 py-2 rounded-xl font-black text-[10px] tracking-widest uppercase transition-all ${filter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border border-slate-100 text-slate-400 hover:text-slate-600'}`}>{f === 'NEUF' ? 'STOCK DISPO' : f}</button>))}</div></div><div className="overflow-x-auto"><table className="w-full text-left border-collapse"><thead><tr className="border-y border-slate-50 bg-slate-50/30 text-[10px] font-black text-slate-400 uppercase tracking-widest">{!isReseller && <th className="px-8 py-4">CODE</th>}{(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && <th className="px-8 py-4">AGENCE</th>}<th className="px-8 py-4">PROFIL</th><th className="px-8 py-4 text-right">PRIX</th><th className="px-8 py-4 text-center">STATUT</th>{currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && <th className="px-8 py-4 text-right">ACTIONS</th>}</tr></thead><tbody className="divide-y divide-slate-50">{loading ? (<tr><td colSpan={6} className="px-8 py-20 text-center"><Loader2 className="w-8 h-8 animate-spin mx-auto text-indigo-200" /></td></tr>) : tickets.length === 0 ? (<tr><td colSpan={6} className="px-8 py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun ticket</td></tr>) : tickets.map((item) => {
        let statusLabel = 'VENDU';
        let statusColor = 'bg-emerald-50 text-emerald-500';

        if (item.status === TicketStatus.NEUF) {
            statusLabel = 'EN STOCK';
            statusColor = 'bg-indigo-50 text-indigo-500';
        } else if (item.status === TicketStatus.ASSIGNE) {
            if (isReseller) {
                statusLabel = 'EN STOCK';
                statusColor = 'bg-indigo-50 text-indigo-500';
            } else {
                statusLabel = 'ASSIGNÉ';
                statusColor = 'bg-purple-50 text-purple-600';
            }
        }

        return (
          <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
            {!isReseller && <td className="px-8 py-6 font-black text-slate-900 tracking-tight">{item.username}</td>}
            {(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && (<td className="px-8 py-6"><div className="flex items-center gap-2"><Building2 className="w-3 h-3 text-slate-300" /><span className="text-[10px] font-black text-slate-500 uppercase">{item.tenants?.name}</span></div></td>)}
            <td className="px-8 py-6 font-black text-xs text-indigo-500 uppercase">{item.ticket_profiles?.name}</td>
            <td className="px-8 py-6 font-black text-slate-900 text-right">{Number(item.ticket_profiles?.price).toLocaleString()} GNF</td>
            <td className="px-8 py-6 text-center"><span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusColor}`}>{statusLabel}</span></td>
            {currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && (<td className="px-8 py-6 text-right"><button onClick={() => handleVerifyDelete(item)} disabled={item.status === TicketStatus.VENDU || item.status === TicketStatus.ASSIGNE} className={`p-2 rounded-lg transition-all ${(item.status === TicketStatus.VENDU || item.status === TicketStatus.ASSIGNE) ? 'text-slate-100 opacity-20' : 'text-slate-300 hover:text-red-600 hover:bg-red-50'}`}><Trash2 className="w-4 h-4" /></button></td>)}
          </tr>
        );
      })}</tbody></table></div></div>
      {ticketToDelete && (<div className="fixed inset-0 z-50 flex items-center justify-center p-4"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isDeleting && setTicketToDelete(null)} /><div className="bg-white w-full max-w-sm rounded-[3rem] p-10 text-center relative z-10 animate-in zoom-in-95 shadow-2xl"><div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6"><AlertTriangle className="w-10 h-10" /></div><h3 className="text-2xl font-black text-slate-900 mb-2 uppercase">Supprimer ?</h3><p className="text-slate-500 text-sm mb-8">Action irréversible sur le ticket <strong>{ticketToDelete.username}</strong>.</p><div className="space-y-3"><button onClick={performDelete} disabled={isDeleting} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-red-700">{isDeleting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "OUI, SUPPRIMER"}</button><button onClick={() => setTicketToDelete(null)} className="w-full py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-xs uppercase">ANNULER</button></div></div></div>)}
    </div>
  );
};
export default Stock;

import React, { useState, useEffect } from 'react';
import { Users, Wallet, Plus, Search, Loader2, TrendingUp, TrendingDown, ArrowRight, History, Ticket, DollarSign, X, Building2, CheckCircle2, AlertCircle, Smartphone, Filter } from 'lucide-react';
import { db } from '../services/db';
import { UserRole, User, TicketStatus } from '../types';

const Resellers: React.FC = () => {
  const [resellers, setResellers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showAssignModal, setShowAssignModal] = useState(false);
  const [selectedReseller, setSelectedReseller] = useState<User | null>(null);
  const [amount, setAmount] = useState('');
  const [method, setMethod] = useState('CASH');
  const [paymentPhone, setPaymentPhone] = useState('');
  const [ticketProfiles, setTicketProfiles] = useState<any[]>([]);
  const [selectedProfileId, setSelectedProfileId] = useState('');
  const [quantity, setQuantity] = useState('50');
  const [processing, setProcessing] = useState(false);
  const [toast, setToast] = useState<any>(null);

  // Nouveaux états pour Admin Global
  const [agencies, setAgencies] = useState<any[]>([]);
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');

  useEffect(() => {
    const init = async () => {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: profile } = await db.from('users').select('*').eq('id', user.id).single();
        setCurrentUser(profile);
        if (profile.role === UserRole.ADMIN_GLOBAL) {
          const { data: tData } = await db.from('tenants').select('id, name').order('name');
          setAgencies(tData || []);
        }
      }
    };
    init();
  }, []);

  useEffect(() => {
    if (currentUser) fetchResellers();
  }, [currentUser, agencyFilter]);

  const fetchResellers = async () => {
    try {
      setLoading(true);
      const isAdminGlobal = currentUser.role === UserRole.ADMIN_GLOBAL;

      let query = db.from('users')
        .select('*, tenants(name)') // Récupère le nom de l'agence
        .eq('role', UserRole.REVENDEUR)
        .eq('is_active', true);

      if (isAdminGlobal) {
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter);
      } else {
        query = query.eq('tenant_id', currentUser.tenant_id);
      }

      const { data: rData } = await query;
      setResellers(rData || []);

      // Charger les profils par défaut si Admin Local (pour Admin Global, on charge au clic sur Assigner)
      if (!isAdminGlobal && currentUser.tenant_id) {
        loadProfiles(currentUser.tenant_id);
      }
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const loadProfiles = async (tenantId: string) => {
    const { data: pData } = await db.from('ticket_profiles')
      .select('id, name, price, tickets(count)')
      .eq('tenant_id', tenantId);
    const availableProfiles = (pData || []).filter((p: any) => (p.tickets?.[0]?.count || 0) > 0);
    setTicketProfiles(availableProfiles);
  };

  const prepareAssign = async (reseller: User) => {
    setSelectedReseller(reseller);
    // Si Admin Global, on doit charger les profils de l'agence du revendeur spécifiquement
    if (currentUser.role === UserRole.ADMIN_GLOBAL) {
        if (reseller.tenant_id) {
            await loadProfiles(reseller.tenant_id);
        } else {
            setTicketProfiles([]); // Pas de tenant, pas de stock
        }
    }
    setShowAssignModal(true);
  };

  const handlePayment = async (e: React.FormEvent) => {
    e.preventDefault(); if (!selectedReseller || !amount || processing) return;

    // Validation du téléphone si méthode mobile
    if ((method === 'MOMO' || method === 'OM')) {
        const rawDigits = paymentPhone.replace(/\D/g, '');
        if (!/^6\d{8}$/.test(rawDigits)) {
            setToast({ type: 'error', message: "Numéro invalide (9 chiffres commençant par 6)." });
            setTimeout(() => setToast(null), 3000);
            return;
        }
    }

    setProcessing(true);
    try {
      const rawDigits = (method === 'MOMO' || method === 'OM') ? paymentPhone.replace(/\D/g, '') : null;
      // IMPORTANT: Utiliser le tenant_id du revendeur pour que la transaction soit liée à la bonne agence
      const targetTenantId = selectedReseller.tenant_id || currentUser.tenant_id;

      const { error } = await db.from('payments').insert({ 
          tenant_id: targetTenantId, 
          reseller_id: selectedReseller.id, 
          amount: Number(amount), 
          payment_method: method, 
          phone_number: rawDigits,
          created_by: currentUser.id 
      });

      if (error) throw error;

      const newBalance = (Number(selectedReseller.balance) || 0) + Number(amount);
      await db.from('users').update({ balance: newBalance }).eq('id', selectedReseller.id);

      setToast({ type: 'success', message: `Compte rechargé de ${Number(amount).toLocaleString()} GNF` }); 
      setShowPaymentModal(false); 
      setAmount('');
      setPaymentPhone('');
      setMethod('CASH');
      fetchResellers();
    } catch (err: any) { setToast({ type: 'error', message: err.message }); } finally { setProcessing(false); }
  };

  const handleAssignStock = async (e: React.FormEvent) => {
    e.preventDefault(); if (!selectedReseller || !selectedProfileId || !quantity || processing) return;
    setProcessing(true);
    try {
      // Vérifier le stock disponible DANS LE TENANT DU REVENDEUR
      const { data: availableTickets } = await db.from('tickets')
        .select('id')
        .eq('tenant_id', selectedReseller.tenant_id) // Contexte Tenant dynamique
        .eq('profile_id', selectedProfileId)
        .eq('status', TicketStatus.NEUF)
        .limit(Number(quantity));

      if (!availableTickets || availableTickets.length < Number(quantity)) throw new Error("Stock insuffisant dans cette agence.");

      const ticketIds = availableTickets.map(t => t.id);
      const { error } = await db.from('tickets').update({ status: TicketStatus.ASSIGNE, assigned_to: selectedReseller.id }).in('id', ticketIds);
      if (error) throw error;

      setToast({ type: 'success', message: `${quantity} tickets ont été assignés.` }); setShowAssignModal(false); fetchResellers();
    } catch (err: any) { setToast({ type: 'error', message: err.message }); } finally { setProcessing(false); }
  };

  return (
    <div className="space-y-10 font-sans pb-40 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[100] p-6 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right ${toast.type === 'success' ? 'bg-emerald-600' : 'bg-red-600'} text-white`}>{toast.type === 'success' ? <CheckCircle2 /> : <AlertCircle />}<p className="font-black uppercase text-[10px] tracking-widest">{toast.message}</p></div>)}

      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm">
        <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestion Revendeurs</h1>
            <p className="text-slate-400 font-medium mt-1">Gérez les soldes et les attributions de stock.</p>
        </div>

        <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
             {/* Filtre Agence pour Admin Global */}
             {currentUser?.role === UserRole.ADMIN_GLOBAL && (
                 <div className="relative min-w-[250px]">
                    <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                    <select 
                        value={agencyFilter} 
                        onChange={(e) => setAgencyFilter(e.target.value)} 
                        className="w-full pl-10 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all cursor-pointer"
                    >
                        <option value="ALL">Toutes les Agences</option>
                        {agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                    </select>
                    <Filter className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300 pointer-events-none" />
                 </div>
             )}

             <div className="relative group flex-1 md:w-64">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-600 transition-colors" />
                <input type="text" placeholder="Rechercher..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none transition-all font-bold text-slate-700" />
             </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {loading ? (
             <div className="col-span-full py-20 flex justify-center"><Loader2 className="w-10 h-10 animate-spin text-slate-200" /></div>
          ) : resellers.filter(r => r.full_name.toLowerCase().includes(searchTerm.toLowerCase())).length === 0 ? (
             <div className="col-span-full py-20 text-center text-slate-400 font-bold uppercase text-xs tracking-widest">Aucun revendeur trouvé</div>
          ) : (
             resellers.filter(r => r.full_name.toLowerCase().includes(searchTerm.toLowerCase())).map(reseller => (
                <div key={reseller.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm group hover:shadow-2xl transition-all duration-300 relative overflow-hidden">
                    {/* Badge Agence pour Admin Global */}
                    {currentUser?.role === UserRole.ADMIN_GLOBAL && (
                        <div className="absolute top-0 right-0 bg-slate-50 px-6 py-3 rounded-bl-[2rem] border-b border-l border-slate-100">
                             <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                                 <Building2 className="w-3 h-3" /> {(reseller as any).tenants?.name || 'Inconnu'}
                             </span>
                        </div>
                    )}

                    <div className="flex justify-between items-start mb-6 mt-2">
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg">
                                {reseller.full_name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-black text-lg text-slate-900 leading-tight">{reseller.full_name}</h3>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest truncate max-w-[150px]">{reseller.email}</p>
                            </div>
                        </div>
                    </div>

                    <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 flex items-center justify-between mb-8">
                        <div>
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Solde Actuel</p>
                            <p className={`text-2xl font-black ${Number(reseller.balance || 0) < 0 ? 'text-red-500' : 'text-emerald-600'}`}>
                                {Number(reseller.balance || 0).toLocaleString()} <span className="text-xs">GNF</span>
                            </p>
                        </div>
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center ${Number(reseller.balance || 0) < 0 ? 'bg-red-50 text-red-500' : 'bg-emerald-50 text-emerald-500'}`}>
                            {Number(reseller.balance || 0) < 0 ? <TrendingDown className="w-5 h-5" /> : <TrendingUp className="w-5 h-5" />}
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => { setSelectedReseller(reseller); setShowPaymentModal(true); setMethod('CASH'); setPaymentPhone(''); }} className="py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg shadow-emerald-100">
                            <DollarSign className="w-4 h-4" /> RECHARGER
                        </button>
                        <button onClick={() => prepareAssign(reseller)} className="py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100">
                            <Ticket className="w-4 h-4" /> ASSIGNER
                        </button>
                    </div>
                </div>
             ))
          )}
      </div>

      {showPaymentModal && selectedReseller && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowPaymentModal(false)} />
          <form onSubmit={handlePayment} className="bg-white w-full max-w-sm rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl">
            <button type="button" onClick={() => setShowPaymentModal(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
            <h2 className="text-2xl font-black mb-8 uppercase text-center text-slate-900 tracking-tight">Encaisser Paiement</h2>
            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montant Reçu (GNF)</label>
                <input type="number" required placeholder="ex: 50000" value={amount} onChange={e => setAmount(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-xl outline-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Méthode</label>
                <div className="relative">
                    <select value={method} onChange={e => setMethod(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black outline-none appearance-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all cursor-pointer">
                    <option value="CASH">Espèces (Cash)</option>
                    <option value="MOMO">MTN Mobile Money</option>
                    <option value="OM">Orange Money</option>
                    </select>
                </div>
              </div>

              {(method === 'MOMO' || method === 'OM') && (
                <div className="animate-in slide-in-from-top-2 fade-in">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Numéro de Téléphone</label>
                  <div className="relative group">
                    <Smartphone className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-emerald-600 transition-colors" />
                    <input type="tel" required placeholder="6xx xx xx xx" value={paymentPhone} onChange={e => setPaymentPhone(e.target.value)} className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-lg outline-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all" />
                  </div>
                </div>
              )}
            </div>
            <button type="submit" disabled={processing} className="w-full mt-10 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95">
              {processing ? <Loader2 className="w-5 h-5 animate-spin" /> : "CRÉDITER LE SOLDE"}
            </button>
          </form>
        </div>
      )}

      {showAssignModal && selectedReseller && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowAssignModal(false)} />
            <form onSubmit={handleAssignStock} className="bg-white w-full max-w-md rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl">
                <button type="button" onClick={() => setShowAssignModal(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                <h2 className="text-2xl font-black mb-2 uppercase text-center text-slate-900 tracking-tight">Assigner du Stock</h2>
                <p className="text-center text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-10">
                    Transférer du stock agence vers {selectedReseller.full_name}
                </p>
                <div className="space-y-6">
                    <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Choisir un forfait</label>
                        <select required value={selectedProfileId} onChange={e => setSelectedProfileId(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black outline-none appearance-none focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all cursor-pointer">
                            <option value="">Sélectionner...</option>
                            {ticketProfiles.map(p => (
                                <option key={p.id} value={p.id}>{p.name} ({p.tickets?.[0]?.count || 0} en stock)</option>
                            ))}
                        </select>
                    </div>
                    <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Quantité à assigner</label>
                        <input type="number" required placeholder="ex: 100" value={quantity} onChange={e => setQuantity(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-xl outline-none focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all" />
                    </div>
                </div>
                <button type="submit" disabled={processing} className="w-full mt-10 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">
                    {processing ? <Loader2 className="w-5 h-5 animate-spin" /> : "VALIDER L'ATTRIBUTION"}
                </button>
            </form>
        </div>
      )}
    </div>
  );
};
export default Resellers;
